import asyncio
import functools

def fetch_record(db_conn, table: str, *, limit: int = 10):
    return db_conn.execute(f"SELECT * FROM {table} LIMIT {limit}").fetchall()

async def main(conn):
    loop = asyncio.get_event_loop()
    fn = functools.partial(fetch_record, conn, "users", limit=50)
    rows = await loop.run_in_executor(None, fn)
    return rows

